const JSON_MIME = 'application/json';
const MAX_BODY_BYTES = 1024 * 1024;
const REQUEST_ID_HEADER = 'x-request-id';
const AUTH_HEADER = 'authorization';

function sendJson(response, statusCode, payload, requestId, extraHeaders = {}) {
  const body = `${JSON.stringify({ ...payload, requestId })}\n`;
  response.writeHead(statusCode, {
    'content-type': `${JSON_MIME}; charset=utf-8`,
    'content-length': Buffer.byteLength(body),
    [REQUEST_ID_HEADER]: requestId,
    ...extraHeaders
  });
  response.end(body);
}

function getRequestId(request) {
  const candidate = request.headers[REQUEST_ID_HEADER];
  const value = Array.isArray(candidate) ? candidate[0] : candidate;

  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (trimmed.length > 0 && trimmed.length <= 120) {
      return trimmed;
    }
  }

  return randomUUID();
}

function createDefaultLogger() {
  return (entry) => {
    // eslint-disable-next-line no-console
    console.log(JSON.stringify(entry));
  };
}

function readBearerToken(request) {
  const candidate = request.headers[AUTH_HEADER];
  const value = Array.isArray(candidate) ? candidate[0] : candidate;
  if (typeof value !== 'string') {
    return null;
  }

  const [scheme, token] = value.split(/\s+/, 2);
  if (!scheme || !token || scheme.toLowerCase() !== 'bearer') {
    return null;
  }

  return token.trim() || null;
