export function createServer({
  store,
  now = () => new Date(),
  logger = createDefaultLogger(),
  writeToken = null
}) {
  return createNodeServer(async (request, response) => {
    const url = new URL(request.url || '/', 'http://localhost');
    const requestId = getRequestId(request);
    const requestStartedAt = process.hrtime.bigint();
    let statusCode = 500;

    const reply = (code, payload, extraHeaders) => {
      statusCode = code;
      return sendJson(response, code, payload, requestId, extraHeaders);
    };

    try {
      if (request.method === 'GET' && url.pathname === '/health') {
        return reply(200, {
          status: 'ok',
          service: 'daio-api',
          timestamp: now().toISOString()
        });
      }

      if (request.method === 'GET' && url.pathname === '/v1/increments') {
        try {
          const increments = await store.list();
          return reply(200, { increments });
        } catch (error) {
          return reply(500, { error: error.message });
        }
      }

      if (request.method === 'POST' && url.pathname === '/v1/increments') {
        if (typeof writeToken === 'string' && writeToken.length > 0) {
          const bearerToken = readBearerToken(request);
          if (bearerToken !== writeToken) {
            return reply(
              401,
              { error: 'Missing or invalid bearer token.' },
              { 'www-authenticate': 'Bearer realm="daio-api"' }
            );
          }
        }

        const body = await readJsonBody(request);
        if (body.error) {
          return reply(body.status, { error: body.error });
        }

        try {
          const increment = await store.add(body.payload, now());
          return reply(201, { increment });
        } catch (error) {
          if (error instanceof ValidationError) {
            return reply(422, { error: error.message });
          }

          return reply(500, { error: error.message });
        }
      }

      if (url.pathname === '/v1/increments') {
        return reply(405, { error: `Method ${request.method} not allowed.` }, { allow: 'GET, POST' });
      }

      return reply(404, { error: 'Not found.' });
    } catch (error) {
      if (!response.writableEnded) {
        return reply(500, { error: error.message });
      }
    } finally {
      const durationMs = Number(process.hrtime.bigint() - requestStartedAt) / 1e6;
      logger({
        timestamp: now().toISOString(),
        type: 'access',
        requestId,
        method: request.method || 'UNKNOWN',
        path: url.pathname,
        statusCode,
        durationMs: Number(durationMs.toFixed(3)),
        remoteAddress: request.socket.remoteAddress || null
      });
    }
  });
}

export async function startServer({ port = 3000, host = '127.0.0.1', filePath, logger, writeToken }) {
  const store = new IncrementStore(filePath);
  await store.init();

  const server = createServer({ store, logger, writeToken });

  await new Promise((resolve) => {
    server.listen(port, host, resolve);
  });

  return server;
}
